var m = variables.mapper || {};
var token = String(m.token || '').trim();
var action = String(m.action || '').toLowerCase().trim();
var recipeId = String(m.recipe_id || '').trim();

var publicActions = ['list', 'get', 'search', 'random'];
var userActions = ['submit', 'my_recipes', 'edit', 'delete'];
var adminActions = ['approve', 'reject', 'pending'];
var allActions = publicActions.concat(userActions).concat(adminActions);

if (allActions.indexOf(action) === -1) {
  var r = { route:'error', statusCode:400, response:{ success:false, error:'Invalid action. Must be one of: '+allActions.join(', ')+'.' } }; r;
} else if (publicActions.indexOf(action) !== -1) {
  if (action === 'get' && !recipeId) {
    var r = { route:'error', statusCode:400, response:{ success:false, error:'recipe_id is required for get.' } }; r;
  } else if (action === 'search' && !String(m.query||'').trim()) {
    var r = { route:'error', statusCode:400, response:{ success:false, error:'query is required for search.' } }; r;
  } else {
    var r = { route:action, category:String(m.category||'').trim(), query:String(m.query||'').trim(), recipe_id:recipeId }; r;
  }
} else {
  if (!token) {
    var r = { route:'error', statusCode:401, response:{ success:false, error:'Authentication required.' } }; r;
  } else {
    try {
      var secret = variables.secrets.my_jwt_secret;
      var decoded = jwtVerify(token, secret);
      var userId = String(decoded.sub||'');
      var userName = String(decoded.name||'');
      var userRole = String(decoded.role||'user');
      if (!userId) {
        var r = { route:'error', statusCode:401, response:{ success:false, error:'Invalid token.' } }; r;
      } else if (adminActions.indexOf(action) !== -1 && userRole !== 'admin') {
        var r = { route:'error', statusCode:403, response:{ success:false, error:'Admin access required.' } }; r;
      } else if ((action==='approve'||action==='reject'||action==='edit'||action==='delete') && !recipeId) {
        var r = { route:'error', statusCode:400, response:{ success:false, error:'recipe_id is required for '+action+'.' } }; r;
      } else if (action === 'pending') {
        var r = { route:'pending', user_id:userId, user_role:userRole }; r;
      } else if (action === 'submit') {
        var title = String(m.title||'').trim();
        var desc = String(m.description||'').trim();
        var ingredients = String(variables.ingredients||'').trim();
        var steps = String(variables.steps||'').trim();
        if (!title||!ingredients||!steps) {
          var r = { route:'error', statusCode:400, response:{ success:false, error:'title, ingredients, and steps are required.' } }; r;
        } else {
          var r = {
            route:'submit', user_id:userId, user_name:userName, user_role:userRole,
            title:title, description:desc, ingredients:ingredients, steps:steps,
            cook_time:Number(m.cook_time)||0, prep_time:Number(m.prep_time)||0,
            servings:Number(m.servings)||1, difficulty:String(m.difficulty||'medium').trim(),
            submit_category:String(m.submit_category||'dinner').trim(),
            image_url:String(m.image_url||'').trim(), tags:String(m.tags||'').trim(),
            created_at:new Date().toISOString()
          }; r;
        }
      } else if (action === 'reject') {
        var reason = String(m.rejection_reason||'').trim();
        if (!reason) reason = 'No reason provided';
        var r = { route:'reject', recipe_id:recipeId, rejection_reason:reason, user_id:userId, user_role:userRole }; r;
      } else if (action === 'edit') {
        var r = {
          route: userRole === 'admin' ? 'edit' : 'edit_own',
          recipe_id:recipeId, user_id:userId, user_role:userRole,
          title:String(m.title||'').trim(), description:String(m.description||'').trim(),
          ingredients:String(variables.ingredients||'').trim(), steps:String(variables.steps||'').trim(),
          cook_time:String(m.cook_time||'').trim(), prep_time:String(m.prep_time||'').trim(),
          servings:String(m.servings||'').trim(), difficulty:String(m.difficulty||'').trim(),
          submit_category:String(m.submit_category||'').trim(),
          image_url:String(m.image_url||'').trim(), tags:String(m.tags||'').trim()
        }; r;
      } else if (action === 'delete') {
        var r = {
          route: userRole === 'admin' ? 'delete' : 'delete_own',
          recipe_id:recipeId, user_id:userId, user_role:userRole
        }; r;
      } else {
        var r = { route:action, user_id:userId, user_name:userName, user_role:userRole, recipe_id:recipeId }; r;
      }
    } catch(e) {
      var r = { route:'error', statusCode:401, response:{ success:false, error:'Invalid or expired token.' } }; r;
    }
  }
}

var data = variables.listData || {};
var rows = data.rows || [];
var cat = (variables.auth || {}).category || '';
if (cat) {
  rows = rows.filter(function(r) { return String(r.category||'').toLowerCase() === cat.toLowerCase(); });
}
var recipes = rows.map(function(r) {
  return {
    id: r._id||'', title: r.title||'', description: r.description||'',
    cook_time: Number(r.cook_time)||0, prep_time: Number(r.prep_time)||0,
    difficulty: r.difficulty||'', category: r.category||'',
    image_url: r.image_url||'', avg_rating: Number(r.avg_rating)||0,
    rating_count: Number(r.rating_count)||0, submitted_by: r.submitted_by||''
  };
});
var result = { success:true, data:recipes, total:recipes.length };
result;

